#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y; scanf("%d %d", &X, &Y);
        int total = 4 * X + Y;
        printf("%d\n", total);
    }
    return 0;
}

